    let mut limitPriceSafetyMultiplierFromMedian: Value = Value::Float(1.045); // todo: when this https://github.com/ccxt/ccxt/issues/22442 is implemented, we'll remove hardcoded value. atm 5% is enough
    let mut market: Value = exchange.market(symbol.clone());
    let mut isSwapFuture: Value = Value::Bool(is_true(&get_value(&market, &Value::Str("swap".to_string()))) || is_true(&get_value(&market, &Value::Str("future".to_string()))));
    assert!(ccxt::runtime::is_true(&(get_value(&get_value(&exchange, &Value::Str("has".to_string())), &Value::Str("fetchBalance".to_string())))));
