    let mut initialQuoteBalance: Value = get_value(&get_value(&balance, &get_value(&market, &Value::Str("quote".to_string()))), &Value::Str("free".to_string()));
    assert!(ccxt::runtime::is_true(&(Value::Bool(!is_equal(&initialQuoteBalance, &Value::Null)))));
