        let mut entryorderPrice: Value = ternary(is_true(&isBuy), multiply(&bestAsk, &limitPriceSafetyMultiplierFromMedian), divide(&bestBid, &limitPriceSafetyMultiplierFromMedian));
        let mut exitorderPrice: Value = ternary(is_true(&isBuy), divide(&bestBid, &limitPriceSafetyMultiplierFromMedian), multiply(&bestAsk, &limitPriceSafetyMultiplierFromMedian)); // todo revise: (tcoMininumCost (exchange, market) / amountToClose) / limitPriceSafetyMultiplierFromMedian;
