        //
        let mut symbol: Value = get_value(&market, &Value::Str("symbol".to_string()));
        let mut entryAmount: Value = tcoGetMinimumAmountForLimitPrice(exchange, market, entryorderPrice);
        let mut entryorderFilled: Value = tcoCreateOrderSafe(exchange, symbol, Value::Str("limit".to_string()), entrySide, entryAmount, entryorderPrice, Value::Map({
            let mut m = indexmap::IndexMap::new();
            m
        }), skippedProperties).await;
        // just for case, cancel any possible unfilled amount (though it is not be expected because the order was fillable)
        tcoTryCancelOrder(exchange, symbol, entryorderFilled, skippedProperties).await;
