        let mut params: Value = Value::Map({
            let mut m = indexmap::IndexMap::new();
            m
        });
        // as we want to close position, we should use 'reduceOnly' to ensure we don't open a margined position accidentally, because some exchanges might have automatically enabled margin-mode (on spot) or hedge-mode (on contracts)
        if is_true(&isSwapFuture) {
            add_element_to_object(&mut params, &Value::Str("reduceOnly".to_string()), Value::Bool(true));
        }
        let mut exitorderFilled: Value = tcoCreateOrderSafe(exchange, symbol, Value::Str("market".to_string()), exitSide, amountToClose, (ternary(is_true(&get_value(&market, &Value::Str("spot".to_string()))), Value::Null, exitorderPrice.clone())), params, skippedProperties).await;
        let mut exitorderFetched: Value = crate::tests_support::shared::fetch_order(exchange.clone(), &[symbol.clone(), get_value(&exitorderFilled, &Value::Str("id".to_string())).clone(), skippedProperties.clone()]).await;
