fn tcoAssertFilledOrder(mut exchange: Value, mut market: Value, mut logPrefix: Value, mut skippedProperties: Value, mut createdOrder: Value, mut fetchedOrder: Value, mut requestedSide: Value, mut requestedAmount: Value) -> Value {
    // test filled amount
    let mut precisionAmount: Value = exchange.safe_string(get_value(&market, &Value::Str("precision".to_string())), Value::Str("amount".to_string()), &[]);
    let mut entryorderAmountString: Value = exchange.number_to_string(requestedAmount.clone());
    let mut filledString: Value = exchange.safe_string(fetchedOrder.clone(), Value::Str("filled".to_string()), &[]);
    assert!(ccxt::runtime::is_true(&(Value::Bool(!is_equal(&filledString, &Value::Null)))));
    // filled amount should be whithin the expected range i.e. if you buy 100 DOGECOIN and amount-precision is 1,
    // and also considering possible roundings in implementation, then filled amount should be between 99 and 101
    let mut maxExpectedFilledAmount: Value = ccxt::precise::Precise::stringAdd(&entryorderAmountString, &precisionAmount);
    let mut minExpectedFilledAmount: Value = ccxt::precise::Precise::stringSub(&entryorderAmountString, &precisionAmount);
    assert!(ccxt::runtime::is_true(&(ccxt::precise::Precise::stringLe(&filledString, &maxExpectedFilledAmount))));
    assert!(ccxt::runtime::is_true(&(ccxt::precise::Precise::stringGe(&filledString, &minExpectedFilledAmount))));
    // order state should be "closed"
    crate::tests_support::shared::assert_order_state(exchange.clone(), &[skippedProperties.clone(), Value::Str("createdOrder".to_string()).clone(), createdOrder.clone(), Value::Str("closed".to_string()).clone(), Value::Bool(false).clone()]);
    crate::tests_support::shared::assert_order_state(exchange.clone(), &[skippedProperties.clone(), Value::Str("fetchedOrder".to_string()).clone(), fetchedOrder.clone(), Value::Str("closed".to_string()).clone(), Value::Bool(true).clone()]);
    // ensure that order side matches
    crate::tests_support::shared::assert_in_array(exchange.clone(), &[skippedProperties.clone(), Value::Str("createdOrder".to_string()).clone(), createdOrder.clone(), Value::Str("side".to_string()).clone(), Value::List(vec![Value::Null, requestedSide.clone()]).clone()]);
    crate::tests_support::shared::assert_in_array(exchange.clone(), &[skippedProperties.clone(), Value::Str("fetchedOrder".to_string()).clone(), fetchedOrder.clone(), Value::Str("side".to_string()).clone(), Value::List(vec![Value::Null, requestedSide.clone()]).clone()]);
    return Value::Bool(true);

    Value::Null
}
