async fn tcoCancelOrder(mut exchange: Value, mut symbol: Value, mut orderId: Value) -> Value {
    let mut logPrefix: Value = crate::tests_support::shared::log_template(exchange.clone(), Value::Str("createOrder".to_string()), Value::List(vec![symbol.clone()]));
    let mut usedMethod: Value = Value::Str("".to_string());
    let mut cancelResult: Value = Value::Null;
    if is_true(&get_value(&get_value(&exchange, &Value::Str("has".to_string())), &Value::Str("cancelOrder".to_string()))) && !is_equal(&orderId, &Value::Null) {
        usedMethod = Value::Str("cancelOrder".to_string());
        cancelResult = crate::live_dispatch::dispatch(&mut exchange, "cancel_order", vec![orderId.clone(), symbol.clone()]).await;
    }  else if is_true(&get_value(&get_value(&exchange, &Value::Str("has".to_string())), &Value::Str("cancelAllOrders".to_string()))) {
        usedMethod = Value::Str("cancelAllOrders".to_string());
        cancelResult = crate::live_dispatch::dispatch(&mut exchange, "cancel_all_orders", vec![symbol.clone()]).await;
    }  else if is_true(&get_value(&get_value(&exchange, &Value::Str("has".to_string())), &Value::Str("cancelOrders".to_string()))) {
        panic!("{}", add(&logPrefix, &Value::Str(" cancelOrders method is not unified yet, coming soon...".to_string())));
    }
    tcoDebug(exchange, symbol, add(&add(&add(&Value::Str("canceled order using ".to_string()), &usedMethod), &Value::Str(":".to_string())), &get_value(&cancelResult, &Value::Str("id".to_string()))));
    return Value::Bool(true);

    Value::Null
}
