fn tcoGetMinimumAmountForLimitPrice(mut exchange: Value, mut market: Value, mut price: Value, mut predefinedAmount: Value) -> Value {
    // this method calculates the minimum realistic order amount:
    // at first it checks the "minimum hardcap limit" (i.e. 7 DOGE), however, if exchange also has "minimum cost" limits,
    // then we need to calculate the amount using cost, because of price is volatile, today's 7 DOGE cost could be 1$
    // but "minimum cost" requirement could be 5$ (which translates to 35 DOGE amount)
    let mut minimumAmount: Value = tcoMininumAmount(exchange, market);
    let mut minimumCost: Value = tcoMininumCost(exchange, market);
    let mut finalAmount: Value = minimumAmount.clone();
    if !is_equal(&minimumCost, &Value::Null) {
        if is_less_than(&multiply(&finalAmount, &price), &minimumCost) {
            finalAmount = divide(&minimumCost, &price);
        }
    }
    if !is_equal(&predefinedAmount, &Value::Null) {
        finalAmount = ccxt::runtime::Math::max(&finalAmount, &predefinedAmount);
    }
    // because it's possible that calculated value might get truncated down in "createOrder" (i.e. 0.129 -> 0.12), we should ensure that final amount * price would bypass minimum cost requirements, by adding the "minimum precision"
    let mut amountPrecision: Value = exchange.safe_number(get_value(&market, &Value::Str("precision".to_string())), Value::Str("amount".to_string()), &[]);
    let mut isTickSizePrecision: Value = Value::Bool(is_equal(&get_value(&exchange, &Value::Str("precisionMode".to_string())), &Value::Int(4)));
    if is_equal(&amountPrecision, &Value::Null) {
        amountPrecision = Value::Float(1e-15); // todo: revise this for better way in future
    }  else {
        // todo: remove after Value::Int(ccxt::runtime::TICK_SIZE) unification
        if !is_true(&isTickSizePrecision) {
            amountPrecision = divide(&Value::Int(1), &ccxt::runtime::Math::pow(&Value::Int(10), &amountPrecision)); // this converts DECIMAL_PRECISION into Value::Int(ccxt::runtime::TICK_SIZE)
        }
    }
    finalAmount = add(&finalAmount, &amountPrecision);
    finalAmount = multiply(&finalAmount, &Value::Float(1.1)); // add around 10% to ensure "cost" is enough
    finalAmount = ccxt::runtime::parse_float(&exchange.decimal_to_precision(finalAmount.clone(), Value::Int(2), get_value(&get_value(&market, &Value::Str("precision".to_string())), &Value::Str("amount".to_string())), &[get_value(&exchange, &Value::Str("precisionMode".to_string()))])); // 2 stands for Value::Int(ccxt::runtime::ROUND_UP) constant, 0 stands for Value::Int(ccxt::runtime::TRUNCATE)
    return finalAmount;

    Value::Null
}
async fn tcoTryCancelOrder(mut exchange: Value, mut symbol: Value, mut order: Value, mut skippedProperties: Value) -> Value {
    let mut orderFetched: Value = crate::tests_support::shared::fetch_order(exchange.clone(), &[symbol.clone(), get_value(&order, &Value::Str("id".to_string())).clone(), skippedProperties.clone()]).await;
    let mut needsCancel: Value = exchange.in_array(get_value(&orderFetched, &Value::Str("status".to_string())), Value::List(vec![Value::Str("open".to_string()), Value::Str("pending".to_string()), Value::Null]));
    // if it was not reported as closed/filled, then try to cancel it
    if is_true(&needsCancel) {
        tcoDebug(exchange, symbol, Value::Str("trying to cancel the remaining amount of partially filled order...".to_string()));
        let _try_result = futures::FutureExt::catch_unwind(std::panic::AssertUnwindSafe(async {
            tcoCancelOrder(exchange, symbol, get_value(&order, &Value::Str("id".to_string()))).await;
         #[allow(unreachable_code)] { Value::Null }})).await;
if let Err(_try_err) = _try_result { let e: Value = panic_to_value(_try_err);
            // order might have been closed/filled already, before 'cancelOrder' call reaches server, so it is tolerable, we don't throw exception
            tcoDebug(exchange, symbol, add(&Value::Str(" a moment ago order was reported as pending, but could not be cancelled at this moment. Exception message: ".to_string()), &to_string_val(&e)));
        }
    }  else {
        tcoDebug(exchange, symbol, Value::Str("order is already closed/filled, no need to cancel it".to_string()));
    }
    return Value::Bool(true);

    Value::Null
}